function onChange(control, oldValue, newValue, isLoading, isTemplate) {
   if (isLoading || newValue === '') {
      return;
   }

	if(g_form.getValue("is_task_executive") + '' == "true"){
		g_form.setValue("can_manage_global_processes",true);
	}

}
